{
  "name": "Orkut Retro Profile Maker",
  "description": "A high-fidelity Orkut (2005-2010) profile reconstructor for generating aesthetic screenshots for modern social media. Includes profile editing, community grids, and specialized screenshot modes."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) throw new Error("Could not find root element to mount to");

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface ProfileData {
  name: string;
  status: string;
  relationship: string;
  city: string;
  country: string;
  birthdate: string;
  fortune: string;
  bio: string;
  profilePic: string;
  stats: {
    trustworthy: number; // 0-3 (ice cubes)
    cool: number; // 0-3
    sexy: number; // 0-3
  };
  scraps: Scrap[];
  testimonials: Testimonial[];
  communities: Community[];
}

export interface Scrap {
  id: string;
  author: string;
  date: string;
  content: string;
  avatar: string;
}

export interface Testimonial {
  id: string;
  author: string;
  content: string;
  avatar: string;
}

export interface Community {
  id: string;
  name: string;
  image: string;
}

export type ScreenshotMode = 'none' | 'post' | 'story';

import React, { useState, useEffect } from 'react';
import { ProfileData, ScreenshotMode } from './types';
import ProfilePage from './components/ProfilePage';
import EditorPanel from './components/EditorPanel';
import Header from './components/Header';

