const App: React.FC = () => {
  const [profile, setProfile] = useState<ProfileData>(INITIAL_PROFILE);
  const [screenshotMode, setScreenshotMode] = useState<ScreenshotMode>('none');

  const handleUpdateProfile = (newData: Partial<ProfileData>) => {
    setProfile(prev => ({ ...prev, ...newData }));
  };

  const getContainerStyle = () => {
    if (screenshotMode === 'post') {
      return 'w-[1080px] h-[1080px] overflow-hidden bg-orkut-bg relative';
    }
    if (screenshotMode === 'story') {
      return 'w-[1080px] h-[1920px] overflow-hidden bg-orkut-bg relative';
    }
    return 'min-h-screen bg-orkut-bg pb-10';
  };

  return (
    <div className="flex flex-col md:flex-row min-h-screen font-orkut">
      {/* Settings Panel - Hidden in screenshot mode */}
      {screenshotMode === 'none' && (
        <EditorPanel 
          profile={profile} 
          onUpdate={handleUpdateProfile} 
          screenshotMode={screenshotMode}
          setScreenshotMode={setScreenshotMode}
        />
      )}

      {/* Main Viewport */}
      <div className={`flex-1 flex flex-col items-center ${screenshotMode !== 'none' ? 'p-0' : 'p-4 overflow-y-auto'}`}>
        <div className={`${getContainerStyle()} shadow-lg`}>
          {screenshotMode !== 'none' && (
             <button 
                onClick={() => setScreenshotMode('none')}
                className="absolute top-4 left-4 z-50 bg-white/80 px-3 py-1 text-sm border border-gray-400 rounded-sm hover:bg-white"
             >
               ← Voltar ao Editor
             </button>
          )}

          <Header name={profile.name} screenshotMode={screenshotMode} />

          <main className={`${screenshotMode === 'none' ? 'max-w-5xl' : 'w-full'} mx-auto px-4 mt-4`}>
             <ProfilePage profile={profile} screenshotMode={screenshotMode} />
          </main>

          {screenshotMode !== 'none' && (
            <div className="absolute bottom-8 right-8 text-orkut-pink font-bold text-4xl opacity-50 select-none">
              orkut.com.br
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default App;

