import React, { useState } from 'react';
import { ProfileData, ScreenshotMode } from '../types';
import Sidebar from './Sidebar';
import Tabs from './Tabs';
import ProfileInfo from './ProfileInfo';
import ScrapsList from './ScrapsList';
import TestimonialsList from './TestimonialsList';

interface ProfilePageProps {
  profile: ProfileData;
  screenshotMode: ScreenshotMode;
}

const ProfilePage: React.FC<ProfilePageProps> = ({ profile, screenshotMode }) => {
  const [activeTab, setActiveTab] = useState('perfil');

  return (
    <div className="flex flex-col md:flex-row gap-4">
      {/* Left Sidebar */}
      <div className="w-full md:w-1/4">
        <Sidebar profile={profile} screenshotMode={screenshotMode} />
      </div>

      {/* Main Content Area */}
      <div className="flex-1 space-y-4">
        <div className="bg-orkut-card-bg border border-orkut-border p-4 rounded-sm">
           <div className="flex items-end justify-between border-b border-orkut-border pb-2 mb-4">
              <h1 className="text-3xl text-orkut-text-blue font-light">{profile.name}</h1>
              <div className="text-xs text-gray-500 italic">"{profile.status}"</div>
           </div>

           <Tabs 
             activeTab={activeTab} 
             onTabChange={setActiveTab} 
             screenshotMode={screenshotMode}
           />

           <div className="mt-4">
             {activeTab === 'perfil' && <ProfileInfo profile={profile} />}
             {activeTab === 'recados' && <ScrapsList scraps={profile.scraps} />}
