           </div>
        </div>
      </div>
    </div>
  );
};

export default ProfilePage;

import React from 'react';
import { ProfileData, ScreenshotMode } from '../types';

interface SidebarProps {
  profile: ProfileData;
  screenshotMode: ScreenshotMode;
}

const Sidebar: React.FC<SidebarProps> = ({ profile, screenshotMode }) => {
  const renderAttribute = (label: string, value: number) => {
    return (
      <div className="flex items-center space-x-1 mb-1">
        <span className="text-[10px] text-gray-600 w-16">{label}:</span>
        <div className="flex space-x-0.5">
          {[1, 2, 3].map(i => (
            <div 
              key={i} 
              className={`w-4 h-4 rounded-sm border border-gray-300 ${i <= value ? 'bg-blue-400 shadow-inner' : 'bg-gray-100'}`}
            ></div>
          ))}
        </div>
      </div>
    );
  };

  return (
    <div className="space-y-4">
      {/* Profile Card */}
      <div className="bg-orkut-card-bg border border-orkut-border p-3 rounded-sm flex flex-col items-center">
        <div className="w-32 h-32 rounded-full border-4 border-white shadow-sm overflow-hidden mb-3">
          <img src={profile.profilePic} alt="Profile" className="w-full h-full object-cover" />
        </div>
        <div className="text-sm font-bold text-orkut-text-blue mb-2 hover:underline cursor-pointer">{profile.name}</div>

        <div className="w-full space-y-2 border-t border-orkut-border pt-2 mt-1">
          {renderAttribute('Confiável', profile.stats.trustworthy)}
          {renderAttribute('Legal', profile.stats.cool)}
          {renderAttribute('Sexy', profile.stats.sexy)}
        </div>

        <div className="w-full mt-3 bg-white border border-orkut-border p-2 text-[10px] italic text-gray-700 leading-tight">
          <span className="font-bold block not-italic mb-1 text-orkut-text-blue">Sorte de hoje:</span>
          {profile.fortune}
        </div>
      </div>

      {/* Communities Section */}
      <div className="bg-orkut-card-bg border border-orkut-border p-3 rounded-sm">
        <div className="flex justify-between items-center mb-2">
          <span className="text-xs font-bold text-orkut-text-blue">Minhas Comunidades</span>
          <span className="text-[10px] text-orkut-text-blue cursor-pointer hover:underline">ver todas</span>
        </div>
        <div className="grid grid-cols-3 gap-2">
          {profile.communities.slice(0, 9).map(comm => (
            <div key={comm.id} className="flex flex-col items-center">
              <img src={comm.image} alt={comm.name} className="w-10 h-10 border border-gray-300 shadow-sm" />
              <span className="text-[9px] text-center text-orkut-text-blue leading-tight mt-1 line-clamp-2">{comm.name}</span>
            </div>
          ))}
        </div>
      </div>

      {/* Profile Menu (Buttons) - Hide in screenshot if requested */}
      <div className="bg-orkut-card-bg border border-orkut-border p-2 rounded-sm space-y-1">
          <button className="w-full text-left px-2 py-1 text-[11px] hover:bg-white text-orkut-text-blue border border-transparent hover:border-orkut-border">Perfil</button>
          <button className="w-full text-left px-2 py-1 text-[11px] hover:bg-white text-orkut-text-blue border border-transparent hover:border-orkut-border">Recados</button>
          <button className="w-full text-left px-2 py-1 text-[11px] hover:bg-white text-orkut-text-blue border border-transparent hover:border-orkut-border">Álbuns</button>
          <button className="w-full text-left px-2 py-1 text-[11px] hover:bg-white text-orkut-text-blue border border-transparent hover:border-orkut-border">Depoimentos</button>
      </div>
    </div>
  );
};

export default Sidebar;

import React from 'react';
import { ScreenshotMode } from '../types';

interface TabsProps {
  activeTab: string;
  onTabChange: (tab: string) => void;
  screenshotMode: ScreenshotMode;
}

const Tabs: React.FC<TabsProps> = ({ activeTab, onTabChange, screenshotMode }) => {
  const tabs = [
    { id: 'perfil', label: 'Perfil' },
    { id: 'recados', label: 'Recados' },
    { id: 'depoimentos', label: 'Depoimentos' },
  ];

  return (
    <div className="flex space-x-1 border-b border-orkut-border">
      {tabs.map(tab => (
        <button
          key={tab.id}
          onClick={() => onTabChange(tab.id)}
          className={`
            px-4 py-1 text-xs font-bold transition-all
            ${activeTab === tab.id 
              ? 'bg-white border-t border-l border-r border-orkut-border -mb-px rounded-t-sm text-orkut-text-blue' 
              : 'text-orkut-text-blue hover:underline'
            }
          `}
        >
          {tab.label}
        </button>
      ))}
    </div>
  );
};

export default Tabs;

