      />

      {/* Main Viewport */}
      <div className={`flex flex-col items-center transition-all duration-300 ${isEditorOpen ? 'blur-sm pointer-events-none' : ''} ${screenshotMode !== 'none' ? 'p-0' : 'p-4 overflow-y-auto'}`}>
